#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 15 (Layer 5): sintesis OOC de npu_axi_top.
#
# Segunda pasada de sintesis, ahora con las interfaces AXI:
#   npu_axi_top = npu_top + npu_dma (master AXI4) + npu_axi_slave (registros)
#
# Referencia de la pasada anterior (solo npu_top):
#   CLB LUTs 51880 (34.5%)  DSP58 51 (11%)  BRAM 1  WNS +1.599 ns
#
# Si el timing no cierra, el script LISTA LOS CAMINOS VIOLADOS directamente,
# sin necesidad de abrir el checkpoint despues (open_checkpoint no carga las
# restricciones y hay que anadir create_clock a mano).
#
# NO EJECUTADO POR CLAUDE: no hay Vivado en el contenedor de construccion.
# La sintaxis Tcl se valido con stubs (tclsh 8.6) en sus tres ramas: exito,
# fallo de timing y fuentes ausentes.
#
# Instala en syn/ y se lanza con:
#   cd ~/vhdl_repo/IP_Cores/NPU
#   bash syn/run_synth_axi.sh
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/rtl/npu_axi_top.vhd" ]; then
  echo "FALLO: falta rtl/npu_axi_top.vhd (corre primero el Paso 14)"; exit 1
fi
mkdir -p "$DIR/syn"
base64 -d << "EOF" > "$DIR/syn/npu_synth_axi.tcl"

EOF
base64 -d << "EOF" > "$DIR/syn/run_synth_axi.sh"

EOF
chmod +x "$DIR/syn/run_synth_axi.sh"
echo "Scripts de sintesis AXI instalados en $DIR/syn/"
echo ""
echo "Para lanzar (necesita el entorno de Vivado cargado):"
echo "  cd $DIR"
echo "  bash syn/run_synth_axi.sh"
)
